package dev.groknull.bpmner.api

/**
 * Repair-strategy safety classification, paired with [RepairKind] on every rule that
 * declares an automated fix:
 *
 * - [SAFE_AUTOMATIC] — the repair may run without operator review.
 * - [SAFE_MANUAL] — the repair is correct but should surface for confirmation.
 * - [LLM_ONLY] — the repair is generated by the language model; never apply unattended.
 *
 * Renamed from the legacy `BpmnRepairSafety` to align with the `RepairSafety` typealias in
 * [BpmnRule.pkl](linter/pkl/schema/BpmnRule.pkl).
 */
enum class RepairSafety {
    SAFE_AUTOMATIC,
    SAFE_MANUAL,
    LLM_ONLY,
}
